import { IMessageComposer } from '@nitrots/nitro-renderer';

export class PurchaseTokenComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(tokenId: number) {
        this._data = [tokenId];
        console.log('[📤] PurchaseTokenComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
